def test_tc_gw_s02_002_doorfr_stays_closed(can_bus):
    msgs = collect_messages(can_bus, MSG_ID_BODY_STATUS, CAPTURE_TIME)
    for msg in msgs:
        assert decode_door_fr(msg) == 0

def test_tc_gw_s02_003_doorfr_periodic(can_bus):
    msgs = collect_messages(can_bus, MSG_ID_BODY_STATUS, CAPTURE_TIME)
    assert len(msgs) > 1
    for msg in msgs:
        assert decode_door_fr(msg) == 0

def test_tc_gw_s02_004_doorfr_immediate(can_bus):
    msgs = collect_messages(can_bus, MSG_ID_BODY_STATUS, CAPTURE_TIME)
    assert decode_door_fr(msgs[0]) == 0

def test_tc_gw_s02_005_doorfr_deterministic(can_bus):
    msgs = collect_messages(can_bus, MSG_ID_BODY_STATUS, CAPTURE_TIME)
    reference = decode_door_fr(msgs[0])
    for msg in msgs:
        assert decode_door_fr(msg) == reference

